style.css:
:root {
	--c64-bg: #352879;
	--c64-panel: #6abfc6;
	--c64-border: #000;
	--c64-text: #000;
	--c64-highlight: #fff;
	--c64-btn-face: #887ecb;
	--c64-btn-face-active: #6abfc6;
	--header-h: 50px;
	--footer-h: 24px;
	--sidebar-w: 320px;
}
*,
:after,
:before {
	box-sizing: border-box;
}
@media (prefers-reduced-motion: no-preference) {
	:root {
		scroll-behavior: smooth;
	}
}
h1,
h2,
h3,
h4,
h5,
h6 {
	margin-top: 0;
	margin-bottom: 0.5rem;
	font-weight: 500;
	line-height: 1.2;
}
p {
	margin-top: 0;
	margin-bottom: 1rem;
}
.container-fluid {
	width: 100%;
	padding-right: var(--bs-gutter-x, 0.75rem);
	padding-left: var(--bs-gutter-x, 0.75rem);
	margin-right: auto;
	margin-left: auto;
}
.row {
	--bs-gutter-x: 1.5rem;
	--bs-gutter-y: 0;
	display: flex;
	flex-wrap: wrap;
	margin-top: calc(-1 * var(--bs-gutter-y));
	margin-right: calc(-0.5 * var(--bs-gutter-x));
	margin-left: calc(-0.5 * var(--bs-gutter-x));
}
.col-12 {
	flex: 0 0 auto;
	width: 100%;
}
.btn {
	display: inline-block;
	font-weight: 400;
	line-height: 1.5;
	color: #212529;
	text-align: center;
	text-decoration: none;
	vertical-align: middle;
	cursor: pointer;
	-webkit-user-select: none;
	user-select: none;
	background-color: transparent;
	border: 1px solid transparent;
	padding: 0.375rem 0.75rem;
	font-size: 1rem;
	border-radius: 0.25rem;
	transition: color 0.15s ease-in-out, background-color 0.15s ease-in-out,
		border-color 0.15s ease-in-out, box-shadow 0.15s ease-in-out;
}
.btn:hover {
	color: #212529;
}
.btn:focus {
	outline: 0;
	box-shadow: 0 0 0 0.25rem rgba(13, 110, 253, 0.25);
}
.btn:disabled {
	pointer-events: none;
	opacity: 0.65;
}
.form-control {
	display: block;
	width: 100%;
	padding: 0.375rem 0.75rem;
	font-size: 1rem;
	font-weight: 400;
	line-height: 1.5;
	color: #212529;
	background-color: #fff;
	background-clip: padding-box;
	border: 1px solid #ced4da;
	-webkit-appearance: none;
	appearance: none;
	border-radius: 0.25rem;
	transition: border-color 0.15s ease-in-out, box-shadow 0.15s ease-in-out;
}
.form-control:focus {
	color: #212529;
	background-color: #fff;
	border-color: #86b7fe;
	outline: 0;
	box-shadow: 0 0 0 0.25rem rgba(13, 110, 253, 0.25);
}
.form-select {
	display: block;
	width: 100%;
	padding: 0.375rem 2.25rem 0.375rem 0.75rem;
	-moz-padding-start: calc(0.75rem - 3px);
	font-size: 1rem;
	font-weight: 400;
	line-height: 1.5;
	color: #212529;
	background-color: #fff;
	background-image: url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg ' viewBox='0 0 16 16'%3e%3cpath fill='none' stroke='%23343a40' stroke-linecap='round' stroke-linejoin='round' stroke-width='2' d='M2 5l6 6 6-6'/%3e%3c/svg%3e");
	background-repeat: no-repeat;
	background-position: right 0.75rem center;
	background-size: 16px 12px;
	border: 1px solid #ced4da;
	border-radius: 0.25rem;
	transition: border-color 0.15s ease-in-out, box-shadow 0.15s ease-in-out;
	appearance: none;
}
.form-select:focus {
	border-color: #86b7fe;
	outline: 0;
	box-shadow: 0 0 0 0.25rem rgba(13, 110, 253, 0.25);
}
.d-flex {
	display: flex !important;
}
.justify-content-center {
	justify-content: center !important;
}
.justify-content-between {
	justify-content: space-between !important;
}
.align-items-center {
	align-items: center !important;
}
.gap-2 {
	gap: 0.5rem !important;
}
.w-100 {
	width: 100% !important;
}
.mb-1 {
	margin-bottom: 0.25rem !important;
}
.mb-2 {
	margin-bottom: 0.5rem !important;
}
.mt-1 {
	margin-top: 0.25rem !important;
}
.text-white {
	--bs-text-opacity: 1;
	color: rgba(255, 255, 255, var(--bs-text-opacity)) !important;
}
.social-links {
	display: flex;
	justify-content: center;
	gap: 20px;
	margin: 15px 0;
	padding-top: 15px;
	border-top: 2px dashed var(--c64-border);
}
.social-link {
	font-size: 24px;
	color: var(--c64-text);
	transition: transform 0.2s, color 0.2s;
}
.social-link:hover {
	transform: scale(1.2);
	color: #0d6efd;
}

body {
	margin: 0;
	-webkit-text-size-adjust: 100%;
	-webkit-tap-highlight-color: transparent;
	background-color: var(--c64-bg);
	color: var(--c64-text);
	font-family: "VT323", monospace;
	font-size: 20px;
	height: 100vh;
	width: 100vw;
	overflow: hidden;
	display: flex;
	flex-direction: column;
}
body.light-mode {
	--c64-bg: #e0e0e0;
	--c64-panel: #f5f5f5;
	--c64-border: #444;
	--c64-text: #111;
	--c64-btn-face: #d0d0d0;
	--c64-btn-face-active: #fff;
}
#app-layout {
	display: flex;
	flex-direction: column;
	height: 100%;
	width: 100%;
}
header {
	height: var(--header-h);
	background-color: var(--c64-panel);
	border-bottom: 4px ridge var(--c64-border);
	display: flex;
	align-items: center;
	justify-content: space-between;
	padding: 0 20px;
	flex-shrink: 0;
	box-shadow: 0 4px 6px rgba(0, 0, 0, 0.3);
	z-index: 100;
}
.brand-title {
	font-family: "Press Start 2P", cursive;
	font-size: 12px;
	color: var(--c64-text);
	text-shadow: 1px 1px 0 var(--c64-highlight);
	text-transform: uppercase;
	letter-spacing: 1px;
}
#workspace {
	display: flex;
	flex: 1;
	overflow: hidden;
	background-color: #222;
}
aside {
	width: var(--sidebar-w);
	background-color: var(--c64-bg);
	border-right: 2px solid var(--c64-border);
	border-left: 2px solid var(--c64-border);
	display: flex;
	flex-direction: column;
	padding: 15px;
	overflow-y: auto;
	flex-shrink: 0;
}
aside.right-panel {
	border-right: none;
	border-left: 2px solid var(--c64-border);
}
#canvas-viewport {
	flex: 1;
	position: relative;
	display: flex;
	align-items: center;
	justify-content: center;
	overflow: auto;
	background-image: linear-gradient(45deg, #333 25%, transparent 25%),
		linear-gradient(-45deg, #333 25%, transparent 25%),
		linear-gradient(45deg, transparent 75%, #333 75%),
		linear-gradient(-45deg, transparent 75%, #333 75%);
	background-size: 20px 20px;
	background-position: 0 0, 0 10px, 10px -10px, -10px 0px;
	padding: 20px;
}
footer {
	height: var(--footer-h);
	background-color: var(--c64-panel);
	border-top: 4px ridge var(--c64-border);
	display: flex;
	align-items: center;
	justify-content: space-between;
	padding: 0 10px;
	font-size: 14px;
	flex-shrink: 0;
	color: var(--c64-text);
}
.panel-section {
	background: var(--c64-panel);
	border: 3px solid var(--c64-border);
	padding: 12px;
	margin-bottom: 15px;
	box-shadow: 4px 4px 0px rgba(0, 0, 0, 0.5);
}
.panel-label {
	font-family: "Press Start 2P", cursive;
	font-size: 10px;
	margin-bottom: 10px;
	display: block;
	color: var(--c64-text);
	text-transform: uppercase;
	border-bottom: 2px dashed var(--c64-text);
	padding-bottom: 6px;
}
.btn-retro {
	font-family: "Press Start 2P", cursive;
	font-size: 10px;
	padding: 10px;
	width: 100%;
	text-align: left;
	background-color: var(--c64-btn-face);
	color: var(--c64-text);
	border: 3px solid #fff;
	border-radius: 0;
	box-shadow: 4px 4px 0px var(--c64-border);
	margin-bottom: 6px;
	display: flex;
	align-items: center;
	justify-content: flex-start;
	gap: 10px;
	text-transform: uppercase;
	transition: transform 0.1s, box-shadow 0.1s;
}
body.light-mode .btn-retro {
	border-color: #000;
	box-shadow: 2px 2px 0px #999;
}
.btn-retro:hover {
	filter: brightness(1.1);
	transform: translate(-1px, -1px);
	box-shadow: 5px 5px 0px var(--c64-border);
}
.btn-retro:active,
.btn-retro.active {
	background-color: var(--c64-btn-face-active);
	transform: translate(2px, 2px);
	box-shadow: 1px 1px 0px var(--c64-border);
	border-style: inset;
}
.btn-action-header {
	width: 40px;
	height: 40px;
	padding: 0;
	display: flex;
	align-items: center;
	justify-content: center;
	font-size: 16px;
}
.control-row {
	display: flex;
	justify-content: space-between;
	align-items: center;
	margin-bottom: 8px;
}
.form-control,
.form-select {
	background: #fff;
	border: 2px solid var(--c64-border);
	color: #000;
	font-family: "VT323", monospace;
	font-size: 18px;
	height: auto;
	padding: 4px 8px;
}
.palette-grid {
	display: grid;
	grid-template-columns: repeat(auto-fill, minmax(28px, 1fr));
	gap: 6px;
}
.swatch {
	width: 100%;
	aspect-ratio: 1;
	border: 1px solid #555;
	cursor: pointer;
	box-shadow: 2px 2px 0px #000;
}
.swatch:hover {
	transform: scale(1.2);
	z-index: 10;
	position: relative;
	border-color: #fff;
}
.swatch.active {
	border: 2px solid #fff;
	box-shadow: 0 0 0 2px #000;
	z-index: 20;
}
#canvas-stack {
	position: relative;
	box-shadow: 0 0 20px rgba(0, 0, 0, 0.8);
}
canvas {
	display: block;
	image-rendering: pixelated;
	background: transparent;
}
#grid-canvas {
	position: absolute;
	top: 0;
	left: 0;
	pointer-events: none;
}
#selection-box {
	position: absolute;
	border: 2px dashed #00ffff;
	box-shadow: 0 0 5px #00ffff;
	display: none;
	pointer-events: none;
	z-index: 20;
	background: rgba(0, 255, 255, 0.1);
}
#scanlines {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%);
	background-size: 100% 4px;
	pointer-events: none;
	z-index: 50;
}
.modal-overlay {
	display: none;
	position: fixed;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background: rgba(0, 0, 0, 0.85);
	z-index: 9999;
	justify-content: center;
	align-items: center;
}
.modal-box {
	background: var(--c64-panel);
	border: 4px solid #fff;
	box-shadow: 8px 8px 0px #000;
	padding: 20px;
	width: 350px;
	text-align: center;
	max-height: 90vh;
	overflow-y: auto;
}
.modal-title {
	font-family: "Press Start 2P";
	font-size: 14px;
	margin-bottom: 15px;
	color: var(--c64-text);
}
.preview-mini {
	width: 80px;
	height: 80px;
	background-image: linear-gradient(45deg, #ccc 25%, transparent 25%),
		linear-gradient(-45deg, #ccc 25%, transparent 25%),
		linear-gradient(45deg, transparent 75%, #ccc 75%),
		linear-gradient(-45deg, transparent 75%, #ccc 75%);
	background-size: 10px 10px;
	border: 2px solid #000;
	margin: 0 auto;
}
#trans-helper {
	width: 100%;
	height: 30px;
	border: 2px solid #fff;
	cursor: pointer;
	background-image: linear-gradient(45deg, #ccc 25%, transparent 25%),
		linear-gradient(-45deg, #ccc 25%, transparent 25%),
		linear-gradient(45deg, transparent 75%, #ccc 75%),
		linear-gradient(-45deg, transparent 75%, #ccc 75%);
	background-size: 10px 10px;
	margin-top: 5px;
}
#pos-display {
	background: rgba(0, 0, 0, 0.7);
	color: #00ff00;
	padding: 4px 8px;
	border-radius: 4px;
	font-family: "Courier New", monospace;
	font-size: 14px;
	min-width: 60px;
	text-align: center;
}
.tool-btn {
	width: 48%;
	margin-bottom: 8px;
}
.tool-row {
	display: flex;
	flex-wrap: wrap;
	justify-content: space-between;
}
.btn-danger {
	background-color: #dc3545 !important;
	color: #fff !important;
}
.btn-success {
	background-color: #28a745 !important;
	color: #fff !important;
}
.status-indicator {
	display: inline-block;
	width: 8px;
	height: 8px;
	border-radius: 50%;
	background: #00ff00;
	margin-right: 8px;
	animation: pulse 2s infinite;
}
@keyframes pulse {
	0% {
		opacity: 1;
	}
	50% {
		opacity: 0.5;
	}
	100% {
		opacity: 1;
	}
}
.toast {
	position: fixed;
	bottom: 30px;
	left: 50%;
	transform: translateX(-50%);
	background: rgba(0, 0, 0, 0.9);
	color: #fff;
	padding: 12px 24px;
	border-radius: 4px;
	font-family: "Press Start 2P";
	font-size: 10px;
	z-index: 10000;
	opacity: 0;
	transition: opacity 0.3s;
	pointer-events: none;
	border: 2px solid #fff;
	box-shadow: 4px 4px 0px rgba(0, 0, 0, 0.5);
}
.toast.show {
	opacity: 1;
}
.help-content {
	text-align: left;
	font-size: 14px;
	line-height: 1.6;
}
.help-section {
	margin-bottom: 15px;
}
.help-title {
	font-family: "Press Start 2P";
	font-size: 10px;
	margin-bottom: 8px;
	color: var(--c64-text);
	border-bottom: 1px solid var(--c64-border);
	padding-bottom: 4px;
}
.help-item {
	display: flex;
	justify-content: space-between;
	margin-bottom: 4px;
}
.help-key {
	background: rgba(0, 0, 0, 0.2);
	padding: 2px 6px;
	border-radius: 3px;
	font-family: monospace;
	font-size: 12px;
}
.help-modal {
	width: 500px;
	max-width: 90vw;
}
.palette-info {
	font-size: 12px;
	color: var(--c64-text);
	margin-top: 5px;
	text-align: center;
}
